import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function d(t,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>在Windows上想要使用gcc编译器需要下载mingw, mingw中带有makefile,不同的mingw版本使用的命令不同</p><table><thead><tr><th>W64devkit（模拟Linux）</th><th>MingW-W64-builds或其他套件 ( Windows cmd命令 )</th></tr></thead><tbody><tr><td>make</td><td>mingw32-make</td></tr><tr><td>cc</td><td>gcc</td></tr><tr><td>rm</td><td>del</td></tr><tr><td>touch</td><td></td></tr><tr><td>ls</td><td></td></tr><tr><td>dir</td><td></td></tr><tr><td>sh</td><td></td></tr><tr><td>mv</td><td></td></tr><tr><td>cp</td><td>copy/xcopy</td></tr><tr><td>sed</td><td></td></tr><tr><td>如常用的linux中makefile写法:</td><td></td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>main:main.cpp</span></span>
<span class="line"><span>	g++ -o $@ $^</span></span>
<span class="line"><span>	./$@</span></span>
<span class="line"><span>	rm -f $@</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>就变为:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>main:main.cpp</span></span>
<span class="line"><span>	g++ -o $@.exe $^</span></span>
<span class="line"><span>	./$@.exe</span></span>
<span class="line"><span>	del $@.exe</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>文件名<code>Makefile</code></p><p>注释是# 通常由以下三部分组成 指令是gcc命令</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>目标文件:前置依赖</span></span>
<span class="line"><span>	\\t需要执行的命令</span></span>
<span class="line"><span>#生成可执行文件</span></span>
<span class="line"><span>main:hello.o main.o</span></span>
<span class="line"><span>	gcc hello.o main.o -o main</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#生成main.o</span></span>
<span class="line"><span>main.o:main.c hello.h</span></span>
<span class="line"><span>	gcc -c main.c -o main.o    #makefile可以自动推导出要生成的目标文件，也可以直接写gcc -c main.c</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#生成hello.o</span></span>
<span class="line"><span>hello.o:hello.c hello.h</span></span>
<span class="line"><span>	gcc-c hello.c</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>makefile是区分空格和制表符的，执行的命令前必须是制表符\\t</p><p><strong>clean清除指定的目标文件</strong> 没有前置依赖 可以删除不需要的中间文件，指令是Linux下的rm删除指令</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>clean:</span></span>
<span class="line"><span>	rm main main.o hello.o</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>定义变量</strong> 定义一个变量其中存储文件名，这样生成文件命令就比较简洁，定义的变量使用时需要使用$取出 换行可以使用\\，其中文件名之间有多少个空格都是允许的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>objects := hello.o\\</span></span>
<span class="line"><span>main.o</span></span>
<span class="line"><span></span></span>
<span class="line"><span>main: $(objects)</span></span>
<span class="line"><span>	gcc $(objects) -o main</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>伪目标</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>.PHONY:伪目标名称</span></span>
<span class="line"><span></span></span>
<span class="line"><span>.PHONY:clean</span></span>
<span class="line"><span></span></span>
<span class="line"><span>clean:</span></span>
<span class="line"><span>	rm main $(objects)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果当前目录下有一个与命令重名的文件（如：clean） 这时就不会执行makefile中的clean命令了，makefile会把它当作是一个生成文件命令，这时就需要把clean声明成伪目标才可以执行</p><p><strong>忽略错误</strong> 当执行的命令出现错误时整个makefile就会被终止，如：rm删除了不存在的文件。有时候不需要那么精确的指令该命令，此时就可以使用忽略错误 在命令前加上-就可以忽略错误了 这对所有命令都适用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>clean:</span></span>
<span class="line"><span>	-rm main main.c</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>忽略错误后makefile就会忽略该错误继续执行，同时在控制台中打印出信息：出现x个错误（已忽略）</p><p><strong>特殊字符</strong> $：取变量值 @：当前目标文件的名称（变量形式） ^：当前目标文件依赖的所有文件（变量形式） &lt;：第一个依赖文件名（变量形式）</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>CC:=gcc</span></span>
<span class="line"><span></span></span>
<span class="line"><span>main:main.c hello.c</span></span>
<span class="line"><span>	-$(CC) -o $@ $^    #-gcc -o main main.c hello.c</span></span>
<span class="line"><span>	-./$@    #-./main执行</span></span>
<span class="line"><span>	-rm ./$@    # -rm ./main</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>变 量</th><th>含 义</th></tr></thead><tbody><tr><td>$*</td><td>表示目标文件的名称，不包含目标文件的扩展名</td></tr><tr><td>$+</td><td>表示所有的依赖文件，这些依赖文件之间以空格分开，按照出现的先后为顺序，其中可能包含重复的依赖文件</td></tr><tr><td>$&lt;</td><td>表示依赖项中第一个依赖文件的名称</td></tr><tr><td>$?</td><td>依赖项中，所有比目标文件时间戳晚的依赖文件，依赖文件之间以空格分开</td></tr><tr><td>$@</td><td>表示目标文件的名称，包含文件扩展名</td></tr><tr><td>$^</td><td>依赖项中，所有不重复的依赖文件，这些文件之间以空格分开</td></tr></tbody></table><h2 id="函数" tabindex="-1"><a class="header-anchor" href="#函数"><span>函数</span></a></h2><p>makefile中有很多函数并且所有的函数都是有返回值的。makefile中函数的格式和C/C++中函数也不同 写法:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>$(函数名 参数1, 参数2, 参数3, ...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>使用频率比较高的函数：wildcard和patsubst。</p><h4 id="wildcard" tabindex="-1"><a class="header-anchor" href="#wildcard"><span>wildcard</span></a></h4><p>获取指定目录下指定类型的文件名，其返回值是以空格分割的、指定目录下的所有符合条件的文件名列表。</p><ul><li>PATTERN 指的是某个或多个目录下的对应的某种类型的文件, 比如当前目录下的.c文件可以写成*.c 可以指定多个目录，每个路径之间使用空格间隔</li><li>返回值：得到的若干个文件的文件列表， 文件名之间使用空格间隔 示例：<code>$(wildcard *.c ./sub/*.c)</code> 返回值格式: <code>a.c b.c c.c d.c e.c f.c ./sub/aa.c ./sub/bb.c</code></li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>$(wildcard PATTERN...)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span># 使用举例: 分别搜索三个不同目录下的 .c 格式的源文件</span></span>
<span class="line"><span>src = $(wildcard /home/robin/a/*.c /home/robin/b/*.c *.c)  # *.c == ./*.c</span></span>
<span class="line"><span># 返回值: 得到一个大的字符串, 里边有若干个满足条件的文件名, 文件名之间使用空格间隔</span></span>
<span class="line"><span>/home/robin/a/a.c /home/robin/a/b.c /home/robin/b/c.c /home/robin/b/d.c e.c f.c</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="patsubst" tabindex="-1"><a class="header-anchor" href="#patsubst"><span>patsubst</span></a></h4><p>按照指定的模式替换指定的文件名的后缀,</p><ul><li>pattern: 这是一个模式字符串, 需要指定出要被替换的文件名中的后缀是什么 文件名和路径不需要关心, 因此使用 % 表示即可 [通配符是 %] 在通配符后边指定出要被替换的后缀, 比如: %.c, 意味着 .c的后缀要被替换掉</li><li>replacement: 这是一个模式字符串, 指定参数pattern中的后缀最终要被替换为什么 还是使用 % 来表示参数pattern 中文件的路径和名字 在通配符 % 后边指定出新的后缀名, 比如: %.o 这表示原来的后缀被替换为 .o</li><li>text: 该参数中存储这要被替换的原始数据</li><li>返回值:函数返回被替换过后的字符串。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span># 有三个参数, 参数之间使用 逗号间隔</span></span>
<span class="line"><span>$(patsubst &lt;pattern&gt;,&lt;replacement&gt;,&lt;text&gt;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>src = a.cpp b.cpp c.cpp e.cpp</span></span>
<span class="line"><span># 把变量 src 中的所有文件名的后缀从 .cpp 替换为 .o</span></span>
<span class="line"><span>obj = $(patsubst %.cpp, %.o, $(src)) </span></span>
<span class="line"><span># obj 的值为: a.o b.o c.o e.o</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="clean" tabindex="-1"><a class="header-anchor" href="#clean"><span>clean</span></a></h3><p>在clean中指定要删除的文件后使用<code>make clean</code>执行删除</p>`,40)]))}const p=e(l,[["render",d]]),r=JSON.parse('{"path":"/cpp/cmake/5/","title":"5 Makefile","lang":"zh-CN","frontmatter":{"title":"5 Makefile","createTime":"2025/06/22 10:20:50","permalink":"/cpp/cmake/5/"},"readingTime":{"minutes":4.6,"words":1379},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/cmake/5 Makefile.md","headers":[]}');export{p as comp,r as data};
